PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?manga ?mangaLabel WHERE {
  ?manga wdt:P31 wd:Q221395 .
  ?manga wdt:P136 wd:Q184402 . MINUS {
    ?manga wdt:P136 wd:Q6529128
  } MINUS {
    ?manga wdt:P136 wd:Q5635475
  }
  ?manga wdt:P1257 ?volumes .
  OPTIONAL {
    ?manga rdfs:label ?mangaLabel .
    FILTER(LANG(?mangaLabel) = 'en')
  }
}
ORDER BY DESC(?volumes)
LIMIT 30

